+    #[test]
+    fn lerp_rgb_same_values_returns_identity() {
+        let a = (128, 64, 200);
+        let mid = PlasmaPalette::lerp_rgb(a, a, 0.5);
+        // With same endpoints, any t should return (approximately) the same value.
+        // Allow +/- 1 for fixed-point rounding.
