+    fn hsv_partial_saturation_desaturates() {
+        // At S=0.5, V=1.0, red hue should have less vivid red
+        let full_sat = PlasmaPalette::hsv_to_rgb(0.0, 1.0, 1.0);
+        let half_sat = PlasmaPalette::hsv_to_rgb(0.0, 0.5, 1.0);
